const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x14532d);this.ball=this.add.circle(60,H-60,10,0xffffff);this.physics.add.existing(this.ball);this.ball.body.setBounce(.8).setDrag(40).setCollideWorldBounds(true);this.hole=this.add.circle(W-50,50,14,0x111827);this.power=260;this.a=-.8;this.ui=this.add.text(10,10,'Tap: Shot');this.input.on('pointerdown',()=>{if(this.over)return;this.ball.body.setVelocity(Math.cos(this.a)*this.power,Math.sin(this.a)*this.power);});this.time.addEvent({delay:80,loop:true,callback:()=>{this.a+=0.08;if(this.a>Math.PI*2)this.a=0;}});this.r=this.input.keyboard.addKey('R');}update(){if(this.r.isDown)this.scene.restart();if(this.over)return;if(Phaser.Math.Distance.Between(this.ball.x,this.ball.y,this.hole.x,this.hole.y)<16){this.over=true;this.add.text(W/2,H/2,'HOLE IN! R').setOrigin(.5);} }}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
